1	// TypeScript port of the o1key Nano Banana async image API client.
2	// Faithful to scripts/generate_image.py from the o1key-nano-banana skill:
3	//   POST {base}/async/v1/generateImage      -> task_id
4	//   GET  {base}/async/v1/tasks/{task_id}     -> poll until success / failure
5	// Server-only module (uses fetch + Buffer). Imported by route handlers.
6	
7	import type { RouteName } from "./types";
8	
9	export const NETWORK_ROUTES: Record<RouteName, string> = {
10	  全球加速: "https://api.o1key.cn",
11	  CF加速: "https://cf-api.o1key.com",
12	  美国直连: "https://api.o1key.com",
13	};
14	export const DEFAULT_ROUTE: RouteName = "全球加速";
15	
16	export const SUBMIT_ENDPOINT = "/async/v1/generateImage";
17	export const TASK_ENDPOINT = "/async/v1/tasks/";
18	export const MAX_BODY_BYTES = 20_000_000; // 20 MB — server rejects larger payloads
19	
20	const MODEL_ID_MAP: Record<string, string> = {
21	  "Nano Banana Pro": "nano-banana-pro",
22	  "Nano Banana 2": "nano-banana-2",
23	  "Nano Banana": "nano-banana",
24	};
25	const RESOLUTION_KEY_MAP: Record<string, string> = { "512": "0.5k", "1K": "1k", "2K": "2k", "4K": "4k" };
26	
27	const SUCCESS = new Set(["success", "succeed", "succeeded", "completed", "done", "finished"]);
28	const FAILURE = new Set([
29	  "failure", "fail", "failed", "error", "expired", "timeout", "timed_out",
30	  "cancel", "canceled", "cancelled", "rejected",
31	]);
32	const RUNNING = new Set([
33	  "submitted", "queued", "pending", "running", "processing", "in_progress", "in-progress", "created",
34	]);
35	
36	export function resolveBaseUrl(route: RouteName, override?: string): string {
37	  if (override && override.trim()) return override.trim().replace(/\/+$/, "");
38	  return NETWORK_ROUTES[route] ?? NETWORK_ROUTES[DEFAULT_ROUTE];
39	}
40	
41	/**
42	 * Translate a friendly model name + resolution + billing into the API model id.
43	 * A value that already looks like a raw id (nano-banana-*) passes through untouched.
44	 */
45	export function buildModelId(modelName: string, resolution: string, billing: string): string {
46	  if (!(modelName in MODEL_ID_MAP) && modelName.toLowerCase().startsWith("nano-banana")) {
47	    return modelName;
48	  }
49	  const base = MODEL_ID_MAP[modelName] ?? "nano-banana-pro";
50	  const isOfficial = billing === "官方" || billing === "official";
51	
52	  if (base === "nano-banana") {
53	    if (isOfficial) throw new Error('模型 "Nano Banana" 仅支持特价计费');
54	    return "nano-banana";
55	  }
56	  const resKey = RESOLUTION_KEY_MAP[resolution] ?? "2k";
57	
58	  if (base === "nano-banana-pro" && resKey === "1k" && !isOfficial) return "nano-banana-pro";
59	  if (base === "nano-banana-2" && resKey === "0.5k") {
60	    if (isOfficial) throw new Error("Nano Banana 2 的 512 分辨率仅支持特价计费");
61	    return "nano-banana-2-0.5k";
62	  }
63	  let id = `${base}-${resKey}`;
64	  if (isOfficial) id += "-official";
65	  return id;
66	}
67	
68	export interface SubmitBody {
69	  model: string;
70	  prompt: string;
71	  size: string;
72	  aspect_ratio?: string;
73	  images?: string[];
74	  google_search?: boolean;
75	}
76	
77	export function buildSubmitBody(opts: {
78	  modelId: string;
79	  prompt: string;
80	  resolution: string;
81	  aspectRatio?: string;
82	  images?: string[];
83	  googleSearch?: boolean;
84	}): SubmitBody {
85	  const body: SubmitBody = {
86	    model: opts.modelId,
87	    prompt: opts.prompt,
88	    size: opts.resolution === "512" ? "512px" : opts.resolution,
89	  };
90	  const ar = opts.aspectRatio;
91	  if (ar && ar !== "auto" && ar !== "智能" && ar !== "") body.aspect_ratio = ar;
92	  if (opts.images && opts.images.length) body.images = opts.images;
93	  if (opts.googleSearch) body.google_search = true;
94	  return body;
95	}
96	
97	// ── Robust payload scanning (mirrors the node/script) ────────────────────────
98	
99	function* payloadSources(payload: unknown): Generator<Record<string, unknown>> {
100	  const queue: unknown[] = [payload];
101	  const seen = new Set<unknown>();
102	  while (queue.length) {
103	    const cur = queue.shift();
104	    if (!cur || typeof cur !== "object" || Array.isArray(cur) || seen.has(cur)) continue;
105	    seen.add(cur);
106	    const rec = cur as Record<string, unknown>;
107	    yield rec;
108	    for (const key of ["data", "result", "response", "output", "task_result", "content"]) {
109	      const v = rec[key];
110	      if (v && typeof v === "object" && !Array.isArray(v)) queue.push(v);
111	    }
112	  }
113	}
114	
115	export function extractTaskId(payload: unknown): string {
116	  for (const src of payloadSources(payload)) {
117	    for (const key of ["task_id", "taskId", "id"]) {
118	      const v = src[key];
119	      if (v) return String(v);
120	    }
121	  }
122	  throw new Error("提交响应中未找到 task_id: " + JSON.stringify(payload).slice(0, 300));
123	}
124	
125	function extractStatusRaw(payload: unknown): string {
126	  const found: string[] = [];
127	  for (const src of payloadSources(payload)) {
128	    for (const key of ["status", "task_status", "state", "task_state"]) {
129	      const v = src[key];
130	      if (v != null && String(v).trim()) found.push(String(v).trim());
131	    }
132	  }
133	  for (const s of found) if (FAILURE.has(s.toLowerCase())) return s;
134	  for (const s of found) if (RUNNING.has(s.toLowerCase())) return s;
135	  for (const s of found) if (SUCCESS.has(s.toLowerCase())) return s;
136	  return found[0] ?? "";
137	}
138	
139	function normalizeStatus(raw: string): "running" | "success" | "failed" {
140	  const s = (raw || "").toLowerCase();
141	  if (FAILURE.has(s) || ["fail", "error", "reject", "timeout", "cancel"].some((t) => s.includes(t))) {
142	    return "failed";
143	  }
144	  if (SUCCESS.has(s)) return "success";
145	  return "running"; // unknown but non-terminal -> keep polling
146	}
147	
148	function extractProgress(payload: unknown): number | null {
149	  for (const src of payloadSources(payload)) {
150	    for (const key of ["progress", "percentage", "percent"]) {
151	      const v = src[key];
152	      if (typeof v === "number") return v > 1 ? v / 100 : v;
153	    }
154	  }
155	  return null;
156	}
157	
158	function extractErrorMessage(payload: unknown): string {
159	  for (const src of payloadSources(payload)) {
160	    const err = src["error"];
161	    if (err && typeof err === "object") {
162	      const e = err as Record<string, unknown>;
163	      for (const key of ["message", "msg", "detail", "reason", "code"]) if (e[key]) return String(e[key]);
164	    } else if (err) {
165	      return String(err);
166	    }
167	    for (const key of [
168	      "fail_reason", "failure_reason", "task_status_msg", "status_msg",
169	      "error_message", "message", "msg", "reason", "detail",
170	    ]) {
171	      if (src[key]) return String(src[key]);
172	    }
173	  }
174	  return "未知错误";
175	}
176	
177	export interface ResultImage {
178	  kind: "url" | "b64";
179	  value: string;
180	}
181	
182	export function extractResultImages(payload: unknown): ResultImage[] {
183	  const out: ResultImage[] = [];
184	  const seen = new Set<string>();
185	  const addUrl = (v: unknown) => {
186	    if (typeof v === "string" && v.startsWith("http") && !seen.has(v)) {
187	      seen.add(v);
188	      out.push({ kind: "url", value: v });
189	    }
190	  };
191	  const addB64 = (v: unknown) => {
192	    if (typeof v === "string" && v && !seen.has(v)) {
193	      seen.add(v);
194	      out.push({ kind: "b64", value: v });
195	    }
196	  };
197	  const handleItem = (item: unknown) => {
198	    if (typeof item === "string") {
199	      if (item.startsWith("http")) addUrl(item);
200	      else if (item.startsWith("data:image")) addB64(item.split(",", 2)[1]);
201	      return;
202	    }
203	    if (!item || typeof item !== "object") return;
204	    const it = item as Record<string, unknown>;
205	    for (const k of ["url", "image_url", "result_url", "download_url"]) addUrl(it[k]);
206	    for (const k of ["b64_json", "base64", "image_base64"]) if (it[k]) addB64(String(it[k]));
207	    for (const ik of ["inline_data", "inlineData"]) {
208	      const inl = it[ik];
209	      if (inl && typeof inl === "object" && (inl as Record<string, unknown>).data) {
210	        addB64(String((inl as Record<string, unknown>).data));
211	      }
212	    }
213	  };
214	  for (const src of payloadSources(payload)) {
215	    for (const k of ["image_url", "result_url", "url", "download_url"]) addUrl(src[k]);
216	    for (const k of ["images", "output_images", "outputs"]) {
217	      const v = src[k];
218	      if (Array.isArray(v)) for (const item of v) handleItem(item);
219	      else if (v) handleItem(v);
220	    }
221	  }
222	  return out;
223	}
224	
225	// ── HTTP ─────────────────────────────────────────────────────────────────────
226	
227	export async function submitTask(baseUrl: string, apiKey: string, body: SubmitBody): Promise<string> {
228	  const url = `${baseUrl}${SUBMIT_ENDPOINT}`;
229	  let res: Response;
230	  try {
231	    res = await fetch(url, {
232	      method: "POST",
233	      headers: { Authorization: `Bearer ${apiKey}`, "Content-Type": "application/json" },
234	      body: JSON.stringify(body),
235	    });
236	  } catch (e) {
237	    throw new Error(
238	      `网络连接失败，无法连接 ${url}：${(e as Error)?.message || e}。请在设置里换一条线路（CF加速 / 美国直连），或检查网络。`,
239	    );
240	  }
241	  const text = await res.text();
242	  if (![200, 201, 202].includes(res.status)) {
243	    throw new Error(`提交失败 HTTP ${res.status}: ${text.slice(0, 500)}`);
244	  }
245	  let payload: unknown;
246	  try {
247	    payload = JSON.parse(text);
248	  } catch {
249	    throw new Error("提交响应非 JSON: " + text.slice(0, 300));
250	  }
251	  return extractTaskId(payload);
252	}
253	
254	export interface PollResult {
255	  status: "running" | "success" | "failed";
256	  progress: number | null;
257	  images: ResultImage[];
258	  error?: string;
259	}
260	
261	export async function pollTaskOnce(baseUrl: string, apiKey: string, taskId: string): Promise<PollResult> {
262	  const url = `${baseUrl}${TASK_ENDPOINT}${encodeURIComponent(taskId)}`;
263	  const res = await fetch(url, { headers: { Authorization: `Bearer ${apiKey}` } });
264	  const text = await res.text();
265	  if (res.status !== 200) throw new Error(`查询任务失败 HTTP ${res.status}: ${text.slice(0, 300)}`);
266	  let payload: unknown;
267	  try {
268	    payload = JSON.parse(text);
269	  } catch {
270	    throw new Error("查询响应非 JSON");
271	  }
272	  const status = normalizeStatus(extractStatusRaw(payload) || "UNKNOWN");
273	  const progress = extractProgress(payload);
274	  if (status === "failed") return { status, progress, images: [], error: extractErrorMessage(payload) };
275	  if (status === "success") return { status, progress, images: extractResultImages(payload) };
276	  return { status: "running", progress, images: [] };
277	}
278	
279	/** Download a result image (URL or base64) into bytes + a file extension. */
280	export async function fetchResultBytes(img: ResultImage, apiKey: string): Promise<{ bytes: Buffer; ext: string }> {
281	  if (img.kind === "url") {
282	    let res: Response;
283	    try {
284	      res = await fetch(img.value, { headers: { Authorization: `Bearer ${apiKey}` } });
285	      if (!res.ok) throw new Error("auth fetch failed");
286	    } catch {
