import { NextResponse } from "next/server";
import { readSettings } from "@/lib/settings";
import { buildModelId, buildSubmitBody, MAX_BODY_BYTES, resolveBaseUrl, submitTask } from "@/lib/o1key";

export const runtime = "nodejs";
export const dynamic = "force-dynamic";

// Submit one or more generation tasks. Returns the upstream task ids as job ids;
// the client polls GET /api/jobs/{id} for each.
export async function POST(req: Request) {
  const s = await readSettings();
  if (!s.apiKey) {
    return NextResponse.json({ error: "未设置 API 令牌，请先在设置中填入 o1key 令牌" }, { status: 400 });
  }

  const body = (await req.json().catch(() => ({}))) as Record<string, unknown>;
  const prompt = String(body.prompt ?? "").trim();
  const model = String(body.model ?? s.defaults.model);
  const resolution = String(body.resolution ?? s.defaults.resolution);
  const aspectRatio = String(body.aspectRatio ?? s.defaults.aspectRatio);
  const billing = String(body.billing ?? s.defaults.billing);
  const count = Math.max(1, Math.min(4, Number(body.count) || 1));
  const baseImage = typeof body.baseImage === "string" ? body.baseImage : "";
  const refImage = typeof body.refImage === "string" ? body.refImage : "";

  if (!prompt) return NextResponse.json({ error: "缺少提示词" }, { status: 400 });
  if (!baseImage) return NextResponse.json({ error: "缺少画布底图" }, { status: 400 });

  let modelId: string;
  try {
    modelId = buildModelId(model, resolution, billing);
  } catch (e) {
    return NextResponse.json({ error: (e as Error).message }, { status: 400 });
  }

  const images = [baseImage];
  if (refImage) images.push(refImage);

  const submitBody = buildSubmitBody({ modelId, prompt, resolution, aspectRatio, images });
  const bytes = Buffer.byteLength(JSON.stringify(submitBody), "utf-8");
  if (bytes > MAX_BODY_BYTES) {
    return NextResponse.json(
      { error: `请求体 ${(bytes / 1e6).toFixed(1)}MB 超过 20MB 上限，请使用更小的图片` },
      { status: 400 },
    );
  }

  const baseUrl = resolveBaseUrl(s.route, s.baseUrlOverride);
  try {
    const ids = await Promise.all(
      Array.from({ length: count }, () => submitTask(baseUrl, s.apiKey, submitBody)),
    );
    return NextResponse.json({ jobs: ids.map((id, index) => ({ id, index })), modelId });
  } catch (e) {
    return NextResponse.json({ error: (e as Error)?.message || "提交失败" }, { status: 502 });
  }
}

import { NextResponse } from "next/server";
import { promises as fs } from "fs";
import path from "path";
import { readSettings } from "@/lib/settings";
import { fetchResultBytes, pollTaskOnce, resolveBaseUrl } from "@/lib/o1key";
import type { JobStatusResponse } from "@/lib/types";

export const runtime = "nodejs";
export const dynamic = "force-dynamic";

const OUTPUT_DIR = path.join(process.cwd(), "output");

async function findExisting(nameNoExt: string): Promise<string | null> {
  for (const ext of [".png", ".jpg", ".webp"]) {
    try {
      await fs.access(path.join(OUTPUT_DIR, nameNoExt + ext));
      return nameNoExt + ext;
    } catch {
      // keep looking
    }
  }
  return null;
}

// Poll one task upstream. On success, download the result image(s) to /output
// and return local media URLs. Idempotent: re-polling a saved job reuses files.
export async function GET(_req: Request, ctx: { params: Promise<{ id: string }> }) {
  const { id } = await ctx.params;
  const s = await readSettings();

  const fail = (error: string): JobStatusResponse => ({ id, status: "failed", progress: null, images: [], error });
  if (!s.apiKey) return NextResponse.json(fail("未设置 API 令牌"));

  const baseUrl = resolveBaseUrl(s.route, s.baseUrlOverride);
  try {
    const poll = await pollTaskOnce(baseUrl, s.apiKey, id);

    if (poll.status === "success") {
      await fs.mkdir(OUTPUT_DIR, { recursive: true });
      const saved: string[] = [];
      for (let i = 0; i < poll.images.length; i++) {
        const nameNoExt = `${id}${poll.images.length > 1 ? `_${i}` : ""}`;
        const existing = await findExisting(nameNoExt);
        if (existing) {
          saved.push(`/api/media/${existing}`);
          continue;
        }
        try {
          const { bytes, ext } = await fetchResultBytes(poll.images[i], s.apiKey);
          const fname = `${nameNoExt}${ext}`;
          await fs.writeFile(path.join(OUTPUT_DIR, fname), bytes);
          saved.push(`/api/media/${fname}`);
        } catch {
          if (poll.images[i].kind === "url") saved.push(poll.images[i].value); // fallback to upstream URL
        }
      }
      const res: JobStatusResponse = { id, status: "success", progress: 1, images: saved };
      return NextResponse.json(res);
    }

    if (poll.status === "failed") {
      return NextResponse.json(fail(poll.error || "生成失败"));
    }

    const res: JobStatusResponse = { id, status: "running", progress: poll.progress, images: [] };
    return NextResponse.json(res);
  } catch (e) {
    return NextResponse.json(fail((e as Error)?.message || "查询失败"));
  }
}

"use client";

import { AnimatePresence, motion } from "motion/react";
import { getAction } from "@/lib/actions";
import { ASPECT_RATIOS, BILLINGS, comboError, MODELS, resolutionsFor } from "@/lib/models";
import { useStudio } from "@/lib/store";
import type { Billing, ModelName, Resolution } from "@/lib/types";
import { cn } from "@/lib/utils";
import { Icon } from "./icons";
import { Button, Segmented, Select } from "./ui";

export function GenerateBar() {
  const image = useStudio((s) => s.image);
  const params = useStudio((s) => s.params);
  const updateParams = useStudio((s) => s.updateParams);
  const activeActionId = useStudio((s) => s.activeActionId);
  const refImage = useStudio((s) => s.refImage);
  const cancelAction = useStudio((s) => s.cancelAction);
  const openUpload = useStudio((s) => s.openUpload);
  const phase = useStudio((s) => s.phase);
  const settings = useStudio((s) => s.settings);
  const openSettings = useStudio((s) => s.openSettings);
  const showToast = useStudio((s) => s.showToast);
  const beginSubmit = useStudio((s) => s.beginSubmit);
  const setJobIds = useStudio((s) => s.setJobIds);
  const setPhase = useStudio((s) => s.setPhase);
  const setError = useStudio((s) => s.setError);

  const action = getAction(activeActionId);
  const busy = phase === "submitting" || phase === "running";
  const resOptions = resolutionsFor(params.model);
  const cErr = comboError(params.model, params.resolution, params.billing);
  const needsRefMissing = !!action?.needsRef && !refImage;
  const canGenerate = !!image && !!params.prompt.trim() && !cErr && !needsRefMissing && !busy;

  function onModel(v: string) {
    const model = v as ModelName;
    const rs = resolutionsFor(model);
    const resolution = rs.includes(params.resolution) ? params.resolution : rs[0];
    let billing = params.billing;
    if (comboError(model, resolution, billing) && !comboError(model, resolution, "特价")) billing = "特价";
    updateParams({ model, resolution, billing });
  }

  async function generate() {
    if (!image) return;
    if (!settings?.hasApiKey) {
      showToast("error", "请先在设置里填入 o1key 令牌");
      openSettings();
      return;
    }
    if (needsRefMissing) {
      showToast("error", action?.refLabel || "请先上传参考图");
      openUpload();
      return;
    }
    if (cErr) {
      showToast("error", cErr);
      return;
    }
    beginSubmit();
    try {
      const res = await fetch("/api/jobs", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          prompt: params.prompt,
          model: params.model,
          resolution: params.resolution,
          aspectRatio: params.aspectRatio,
          billing: params.billing,
          count: params.count,
          baseImage: image.src,
          refImage: refImage || undefined,
        }),
      }).then((r) => r.json());

      if (res.error) {
        setError(res.error);
        setPhase("error");
        showToast("error", res.error);
        return;
      }
      setJobIds((res.jobs as { id: string }[]).map((j) => j.id));
      setPhase("running");
    } catch (e) {
      setError((e as Error).message);
      setPhase("error");
      showToast("error", "提交失败，请检查网络或线路");
    }
  }

  if (!image) return null;

  return (
    <div className="pointer-events-none absolute inset-x-0 bottom-0 z-30 flex justify-center px-4 pb-4">
      <AnimatePresence>
        <motion.div
          key="genbar"
          initial={{ opacity: 0, y: 24 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ type: "spring", stiffness: 260, damping: 28 }}
          className="glass pointer-events-auto w-[min(920px,96vw)] rounded-panel p-3.5"
        >
          {/* action chip + reference */}
          <div className="mb-2.5 flex flex-wrap items-center gap-2">
            {action ? (
              <span className="inline-flex items-center gap-2 rounded-full bg-white/[0.06] py-1 pl-2 pr-1 text-sm">
                <span className="flex h-6 w-6 items-center justify-center rounded-full bg-white/10 text-accent">
                  <Icon name={action.icon} size={13} weight="bold" />
                </span>
                <span className="font-medium text-fg">{action.label}</span>
                <button
                  onClick={cancelAction}
                  className="flex h-6 w-6 items-center justify-center rounded-full text-fg-mute hover:bg-white/10 hover:text-fg"
                  aria-label="取消操作"
                >
                  <Icon name="X" size={13} />
                </button>
              </span>
            ) : (
              <span className="text-sm text-fg-mute">未选操作 · 点击图片选操作，或直接写提示词</span>
            )}

            {action?.needsRef ? (
              refImage ? (
                <button
                  onClick={openUpload}
                  className="group inline-flex items-center gap-2 rounded-full border border-line bg-panel-2 py-1 pl-1 pr-3 text-xs text-fg-dim hover:border-line-2"
                  title="更换参考图"
                >
                  {/* eslint-disable-next-line @next/next/no-img-element */}
                  <img src={refImage} alt="参考" className="h-6 w-6 rounded-full object-cover" />
                  参考图
                  <Icon name="ArrowClockwise" size={12} className="text-fg-mute group-hover:text-fg" />
                </button>
              ) : (
                <button
                  onClick={openUpload}
                  className="inline-flex items-center gap-1.5 rounded-full border border-amber-400/40 bg-amber-400/10 px-3 py-1 text-xs text-accent"
                >
                  <Icon name="UploadSimple" size={13} />
                  补上参考图
                </button>
              )
            ) : null}
          </div>

          {/* prompt */}
          <textarea
            value={params.prompt}
            onChange={(e) => updateParams({ prompt: e.target.value })}
            placeholder="描述你想要的效果，或保留操作自动生成的提示词…"
            rows={2}
            className="w-full resize-none rounded-control border border-line bg-panel-2/60 p-3 text-sm leading-relaxed text-fg placeholder:text-fg-mute focus:border-accent focus:outline-none"
          />

          {/* controls + generate */}
          <div className="mt-2.5 flex flex-wrap items-center gap-2">
            <Select
              value={params.model}
              onChange={onModel}
              options={MODELS.map((m) => ({ value: m.name, label: m.name }))}
              className="w-[168px]"
            />
            <Select
              value={params.resolution}
              onChange={(v) => updateParams({ resolution: v as Resolution })}
              options={resOptions.map((r) => ({ value: r, label: r }))}
              className="w-[92px]"
            />
            <Select
              value={params.aspectRatio}
              onChange={(v) => updateParams({ aspectRatio: v })}
              options={ASPECT_RATIOS.map((a) => ({ value: a, label: a === "auto" ? "自动比例" : a }))}
              className="w-[116px]"
            />
            <Select
              value={params.billing}
              onChange={(v) => updateParams({ billing: v as Billing })}
              options={BILLINGS.map((b) => ({ value: b, label: b }))}
              className="w-[88px]"
            />
            <Segmented
              value={params.count}
              onChange={(v) => updateParams({ count: v })}
              options={[1, 2, 3, 4].map((n) => ({ value: n, label: `×${n}` }))}
            />

            <div className="ml-auto flex items-center gap-3">
              <span className="hidden text-xs text-fg-mute sm:block">按 o1key 计费</span>
              <Button variant="primary" onClick={generate} disabled={!canGenerate} className="px-6">
                {busy ? (
                  <>
                    <Icon name="CircleNotch" size={16} className="animate-spin" />
                    生成中
                  </>
                ) : (
                  <>
                    <Icon name="Lightning" size={16} weight="fill" />
                    生成
                  </>
                )}
              </Button>
            </div>
          </div>

          {cErr ? (
            <div className={cn("mt-2 flex items-center gap-1.5 text-xs text-amber-300")}>
              <Icon name="Warning" size={13} />
              {cErr}
            </div>
          ) : null}
        </motion.div>
      </AnimatePresence>
    </div>
  );
}

